func TestNotifyWorker_SenderError(t *testing.T) {
	sourceID := "src-1"
	releaseID := "rel-1"

	store := &mockNotifyStore{
		releases: map[string]*models.Release{
			releaseID: {ID: releaseID, SourceID: sourceID, Version: "v1.0.0", RawData: json.RawMessage(`{}`)},
