    13→	"github.com/sentioxyz/changelogue/internal/models"
    14→)
    15→
    16→// mockSubscriptionsStore implements SubscriptionsStore for testing.
    17→type mockSubscriptionsStore struct {
    18→	subscriptions []models.Subscription
    19→	created       *models.Subscription
    20→	updated       *models.Subscription
    21→	deleted       string
    22→	batchCreated []models.Subscription
    23→	batchErr     error
    24→	listErr       error
    25→	createErr     error
    26→	getErr        error
    27→	updateErr     error
    28→	deleteErr     error
    29→}
    30→
    31→func (m *mockSubscriptionsStore) ListSubscriptions(_ context.Context, page, perPage int) ([]models.Subscription, int, error) {
    32→	if m.listErr != nil {
    33→		return nil, 0, m.listErr
    34→	}
    35→	return m.subscriptions, len(m.subscriptions), nil
    36→}
    37→
    38→func (m *mockSubscriptionsStore) CreateSubscription(_ context.Context, sub *models.Subscription) error {
    39→	if m.createErr != nil {
    40→		return m.createErr
    41→	}
    42→	sub.ID = "sub-001"
    43→	sub.CreatedAt = time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
    44→	m.created = sub
    45→	return nil
    46→}
    47→
    48→func (m *mockSubscriptionsStore) GetSubscription(_ context.Context, id string) (*models.Subscription, error) {
    49→	if m.getErr != nil {
    50→		return nil, m.getErr
    51→	}
    52→	for i := range m.subscriptions {
    53→		if m.subscriptions[i].ID == id {
    54→			return &m.subscriptions[i], nil
    55→		}
    56→	}
    57→	return nil, fmt.Errorf("not found")
    58→}
    59→
    60→func (m *mockSubscriptionsStore) UpdateSubscription(_ context.Context, id string, sub *models.Subscription) error {
    61→	if m.updateErr != nil {
    62→		return m.updateErr
    63→	}
    64→	for i := range m.subscriptions {
    65→		if m.subscriptions[i].ID == id {
    66→			m.updated = sub
    67→			return nil
    68→		}
    69→	}
    70→	return fmt.Errorf("not found")
    71→}
    72→
    73→func (m *mockSubscriptionsStore) CreateSubscriptionBatch(_ context.Context, subs []models.Subscription) ([]models.Subscription, error) {
    74→	if m.batchErr != nil {
    75→		return nil, m.batchErr
    76→	}
    77→	var result []models.Subscription
    78→	for i, sub := range subs {
    79→		sub.ID = fmt.Sprintf("sub-batch-%d", i)
    80→		sub.CreatedAt = time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
    81→		result = append(result, sub)
    82→	}
    83→	m.batchCreated = result
    84→	return result, nil
    85→}
    86→
    87→func (m *mockSubscriptionsStore) DeleteSubscription(_ context.Context, id string) error {
    88→	if m.deleteErr != nil {
    89→		return m.deleteErr
    90→	}
    91→	for _, s := range m.subscriptions {
    92→		if s.ID == id {
    93→			m.deleted = id
    94→			return nil
    95→		}
    96→	}
    97→	return fmt.Errorf("not found")
    98→}
    99→
   100→func setupSubscriptionsMux(store SubscriptionsStore) *http.ServeMux {
   101→	h := NewSubscriptionsHandler(store)
   102→	mux := http.NewServeMux()
   103→	mux.HandleFunc("GET /subscriptions", h.List)
   104→	mux.HandleFunc("POST /subscriptions", h.Create)
   105→	mux.HandleFunc("POST /subscriptions/batch", h.BatchCreate)
   106→	mux.HandleFunc("GET /subscriptions/{id}", h.Get)
