   738→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   739→// This follows the transactional outbox pattern for zero-loss guarantee.
   740→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error {
   741→	tx, err := s.pool.Begin(ctx)
   742→	if err != nil {
   743→		return fmt.Errorf("begin tx: %w", err)
   744→	}
   745→	defer tx.Rollback(ctx)
   746→
   747→	var runID string
   748→	err = tx.QueryRow(ctx,
   749→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   750→		 VALUES ($1, $2, $3, 'pending')
   751→		 RETURNING id`, projectID, trigger, version,
   752→	).Scan(&runID)
   753→	if err != nil {
   754→		return fmt.Errorf("insert agent run: %w", err)
   755→	}
   756→
   757→	if s.river != nil {
   758→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   759→			AgentRunID: runID,
   760→			ProjectID:  projectID,
   761→			Version:    version,
   762→		}, nil)
   763→		if err != nil {
   764→			return fmt.Errorf("enqueue agent job: %w", err)
   765→		}
   766→	}
   767→
   768→	return tx.Commit(ctx)
   769→}
