      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  };

  const allProjectIds = projectsData?.data.map((p) => p.id) ?? [];
  const allSourceIds = allSourcesData?.map((s) => s.id) ?? [];

