          </div>
          {selectedProjectIds.length > 0 && (
            <p className="text-xs text-muted-foreground">{selectedProjectIds.length} selected</p>
          )}
        </div>
      )}

      {/* SOURCE SELECTION */}
      {type === "source" && isEditing && (
