              </div>
            ))}
            {sourcesByProject.length === 0 && (
              <p className="text-sm text-muted-foreground px-2 py-1">No sources found</p>
            )}
          </div>
          {selectedSourceIds.length > 0 && (
            <p className="text-xs text-muted-foreground">{selectedSourceIds.length} selected</p>
