   155→// BatchCreate handles POST /subscriptions/batch — creates multiple subscriptions at once.
   156→func (h *SubscriptionsHandler) BatchCreate(w http.ResponseWriter, r *http.Request) {
   157→	var input BatchSubscriptionInput
   158→	if err := DecodeJSON(r, &input); err != nil {
   159→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   160→		return
   161→	}
   162→	input.Type = strings.TrimSpace(input.Type)
