   795→// CreateSemanticRelease inserts a semantic release and its source release links
   796→// in a single transaction. The sr.ID field is populated on success.
   797→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   798→	tx, err := s.pool.Begin(ctx)
   799→	if err != nil {
   800→		return fmt.Errorf("begin tx: %w", err)
   801→	}
   802→	defer tx.Rollback(ctx)
   803→
   804→	err = tx.QueryRow(ctx,
   805→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   806→		 VALUES ($1, $2, $3, $4, $5)
   807→		 RETURNING id, created_at`,
   808→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   809→	).Scan(&sr.ID, &sr.CreatedAt)
   810→	if err != nil {
   811→		return fmt.Errorf("insert semantic release: %w", err)
   812→	}
   813→
   814→	for _, relID := range releaseIDs {
   815→		_, err = tx.Exec(ctx,
   816→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   817→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   818→			sr.ID, relID,
   819→		)
   820→		if err != nil {
   821→			return fmt.Errorf("insert semantic release source: %w", err)
   822→		}
   823→	}
   824→
   825→	return tx.Commit(ctx)
   826→}
