   828→// UpdateAgentRunResult sets the semantic_release_id for a completed agent run.
   829→func (s *PgStore) UpdateAgentRunResult(ctx context.Context, id string, semanticReleaseID string) error {
   830→	tag, err := s.pool.Exec(ctx,
